mapper.select:
SELECT c.id, c.course_code, c.course_name, c.credit, c.hours, ct.type_name, c.semester, c.max_students, c.current_students FROM course c LEFT JOIN course_type ct ON c.type_id = ct.type_id
AND c.course_name LIKE CONCAT('%', #{courseName}, '%')
AND c.semester = #{semester}
AND c.type_id = #{typeId}
ORDER BY c.course_code
